/**
 * Tax brackets:
 *   income <= 0          : throws INVALID_INCOME
 *   0 < income < 10_000  : 0%  (tax = 0)
 *   10_000 <= income <= 50_000  : 10% flat
 *   50_001 <= income <= 150_000 : 25% flat
 *   income > 150_000            : 40% flat
 */

export class TaxError extends Error {
  constructor(
    public readonly code: string,
    message: string
  ) {
    super(message);
    this.name = "TaxError";
  }
}

export function calculateTax(income: number): number {
  if (income <= 0) {
    throw new TaxError(
      "INVALID_INCOME",
      `Income must be a positive number, received: ${income}`
    );
  }

  if (income < 10_000) {
    return 0;
  }

  if (income <= 50_000) {
    return income * 0.10;
  }

  if (income <= 150_000) {
    return income * 0.25;
  }

  return income * 0.40;
}

